#!/usr/bin/env node

import { execFileSync } from 'node:child_process';
import { mkdir, writeFile } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';

const args = process.argv.slice(2);

function takeFlag(name) {
  const index = args.indexOf(name);
  if (index < 0) return undefined;
  const value = args[index + 1];
  if (!value || value.startsWith('--')) {
    throw new Error(`${name} requires a value`);
  }
  args.splice(index, 2);
  return value;
}

function hasFlag(name) {
  const index = args.indexOf(name);
  if (index < 0) return false;
  args.splice(index, 1);
  return true;
}

const scratch = resolve(takeFlag('--scratch') ?? '.a0/model-scratch/flux-1-schnell');
const output = takeFlag('--output') ?? '.a0/runs/unsound-diffusion/real/flux-1-schnell.local-preflight.json';
const minFreeGiB = Number(takeFlag('--min-free-gib') ?? process.env.FLUX_SCHNELL_MIN_FREE_GIB ?? '35');
const requireR2 = hasFlag('--require-r2');

if (args.length > 0) {
  throw new Error(`unknown arguments: ${args.join(' ')}`);
}

function commandVersion(command, versionArgs = ['--version']) {
  try {
    return execFileSync(command, versionArgs, {
      encoding: 'utf8',
      stdio: ['ignore', 'pipe', 'pipe'],
    }).trim();
  } catch (error) {
    return null;
  }
}

async function main() {
  await mkdir(scratch, { recursive: true });

  const blockers = [];
  const pythonVersion = commandVersion('python3');
  if (pythonVersion === null) {
    blockers.push('python3 is required for encode-knot.py and sidecar generation');
  }

  let freeBytes = 0;
  let dfRaw = '';
  try {
    dfRaw = execFileSync('df', ['-Pk', scratch], { encoding: 'utf8' }).trim();
    const lines = dfRaw.split(/\r?\n/);
    const fields = lines[1]?.trim().split(/\s+/) ?? [];
    const freeKiB = Number(fields[3] ?? '0');
    if (Number.isFinite(freeKiB) && freeKiB > 0) {
      freeBytes = freeKiB * 1024;
    }
  } catch (error) {
    blockers.push(`unable to inspect free disk for ${scratch}`);
  }

  const minFreeBytes = Math.ceil(minFreeGiB * 1024 ** 3);
  if (freeBytes < minFreeBytes) {
    blockers.push(
      `scratch volume has ${(freeBytes / 1024 ** 3).toFixed(1)}GiB free; ` +
      `FLUX.1-schnell direct KNOT build requires at least ${minFreeGiB}GiB`
    );
  }

  const hfToken = process.env.HF_TOKEN || process.env.HUGGINGFACE_TOKEN || '';
  const r2Token = process.env.R2_TOKEN || '';
  if (requireR2 && r2Token.length === 0) {
    blockers.push('R2_TOKEN is required to upload flux-1-schnell KNOT artifacts');
  }

  const report = {
    modelId: 'flux-1-schnell',
    sourceHf: 'black-forest-labs/FLUX.1-schnell',
    license: 'Apache-2.0',
    checkedAt: new Date().toISOString(),
    status: blockers.length === 0 ? 'ready' : 'blocked',
    scratch,
    minFreeGiB,
    freeGiB: Number((freeBytes / 1024 ** 3).toFixed(2)),
    freeBytes,
    pythonVersion,
    hfAccess: hfToken.length > 0 ? 'token' : 'anonymous-public',
    r2Access: r2Token.length > 0 ? 'token' : 'missing',
    requireR2,
    directWriter: {
      enabled: true,
      env: 'KNOT_STREAM_DIRECT=1',
      headerReserveBytes: Number(process.env.KNOT_HEADER_RESERVE_BYTES ?? 2 * 1024 * 1024),
      reclaimEncodedShards: true,
      reclaimEnv: 'KNOT_DELETE_SHARDS_AFTER_ENCODE=1',
    },
    blockers,
    nextTargets: [
      'distributed-inference:build-flux-schnell-knot',
      'distributed-inference:upload-flux-schnell-knot',
      '@a0n/inference-runtime:admit-unsound-flux-schnell-production',
    ],
    df: dfRaw,
  };

  await mkdir(dirname(output), { recursive: true });
  await writeFile(output, `${JSON.stringify(report, null, 2)}\n`);
  console.log(`wrote ${output}`);
  console.log(`${report.status}: ${report.blockers.length} blocker(s)`);
  for (const blocker of blockers) {
    console.log(`  - ${blocker}`);
  }

  if (blockers.length > 0) {
    process.exitCode = 2;
  }
}

await main();
